addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request))
})

async function handleRequest(request) {
  try {
    const url = new URL(request.url)
    const path = url.pathname

    if (path === '/send-email') {
      return await sendEmail(request)
    } else if (path === '/create-payment') {
      return await createPayment(request)
    } else {
      return new Response('Not Found', { status: 404 })
    }
  } catch (error) {
    return new Response('Internal Server Error', { status: 500 })
  }
}

async function sendEmail(request) {
  const apiKey = 'SENDGRID_API_KEY'
  const sendGridUrl = 'https://api.sendgrid.com/v3/mail/send'

  const body = await request.json()
  const emailData = {
    personalizations: [{ to: [{ email: body.to }] }],
    from: { email: body.from },
    subject: body.subject,
    content: [{ type: 'text/plain', value: body.message }]
  }

  const response = await fetch(sendGridUrl, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(emailData)
  })

  if (!response.ok) {
    return new Response('Failed to send email', { status: response.status })
  }

  return new Response('Email sent successfully', { status: 200 })
}

async function createPayment(request) {
  const stripeSecretKey = 'STRIPE_SECRET_KEY'
  const stripeUrl = 'https://api.stripe.com/v1/charges'

  const body = await request.json()
  const paymentData = new URLSearchParams()
  paymentData.append('amount', body.amount)
  paymentData.append('currency', body.currency)
  paymentData.append('source', body.source)

  const response = await fetch(stripeUrl, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${stripeSecretKey}`,
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: paymentData.toString()
  })

  if (!response.ok) {
    return new Response('Failed to create payment', { status: response.status })
  }

  return new Response('Payment created successfully', { status: 200 })
}